return items.map(item => {
  const body = item.json.body;

  // 📞 1. Padronizar telefone (55 + DDD + número)
  let phone = body.buyer_phone_raw || body.buyer_phone || "";
  phone = phone.replace(/\D/g, "");

  if (!phone.startsWith("55")) {
    phone = "55" + phone;
  }

  // 🎯 2. Extrair "Polo X" de forma inteligente
  const extractPolo = (text) => {
    if (!text) return null;

    // Pega tudo depois de "Polo"
    const match = text.match(/Polo\s+(.+)/i);
    if (!match) return null;

    let polo = match[1];

    // Remove tudo depois de separadores comuns
    polo = polo.split(/[-|–—(]/)[0];

    // Remove palavras comuns que podem vir depois
    polo = polo.replace(/\b(Turma|Noite|Manhã|Tarde|Online|EAD)\b.*$/i, "");

    // Limpeza final
    polo = polo.trim();

    return polo ? `Polo ${polo}` : null;
  };

  const poloProduto = extractPolo(body.product_name);
  const poloOferta = extractPolo(body.offer_title);

  const poloFinal = poloProduto || poloOferta || null;

  return {
    json: {
      telefone_formatado: phone,
      polo: poloFinal
    }
  };
});

