(() => {
  const d = new Date();
  const options = { timeZone: 'America/Sao_Paulo' };

  const data = d.toLocaleDateString('pt-BR', options);
  const hora = d.toLocaleTimeString('pt-BR', {
    ...options,
    hour: '2-digit',
    minute: '2-digit'
  });

  return `${data} ${hora}`;
})()
}}
